        /// <summary>
        /// Create a martial strike with automatic stamina cost scaling
        /// </summary>
        public static AbilityDefinition CreateMartialStrike(int id, string name, AbilitySchool school,
            int minDmg, int maxDmg, int staminaCost = 0, int tier = 1)
        {
            int cost = staminaCost > 0 ? staminaCost : AbilityCostScaling.GetStaminaCost(tier);

            return new AbilityDefinition()
                .WithId(id)
                .WithName(name)
                .InSchool(school)
                .InCircle(tier) // Martial tier maps to circle
                .WithStaminaCost(cost)
                .WithCooldown(tier * 1.5) // Basic cooldown scaling for martial
                .Targeting(AbilityTargetType.SingleTarget, 2)
                .AsInstant()
                .WithDamage(minDmg, maxDmg, VystiaDamageType.Physical);
        }

        /// <summary>
        /// Create a finisher that consumes combo points with automatic stamina cost scaling
        /// </summary>
        public static AbilityDefinition CreateFinisher(int id, string name, AbilitySchool school,
            int baseDmg, int dmgPerStack, int staminaCost = 0, int tier = 3)
        {
            int cost = staminaCost > 0 ? staminaCost : AbilityCostScaling.GetStaminaCost(tier);

            var ability = new AbilityDefinition()
                .WithId(id)
                .WithName(name)
                .InSchool(school)
                .InCircle(tier)
                .WithStaminaCost(cost)
                .WithCooldown(6.0) // Finishers have fixed 6 second cooldown
                .Targeting(AbilityTargetType.SingleTarget, 2)
                .AsInstant()
                .AsFinisher();

            // Base damage plus bonus per consumed stack
            ability.Effects.Add(new AbilityEffect
            {
                Type = AbilityEffectType.DirectDamage,
                MinValue = baseDmg,
                MaxValue = baseDmg,
                DamageType = VystiaDamageType.Physical
            });

            ability.Effects.Add(new AbilityEffect
            {
                Type = AbilityEffectType.ConsumeStack,
                StackType = StackType.Combo
            });

            return ability;
        }

        #endregion
    }

    #endregion
}
